prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?created ?org ?orgLabel WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org rdfs:label ?orgLabel . }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDir ?gwDefault WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?gw a bboExt:ExclusiveGateway .
  ?gw tai:belongsTo ?choreo .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
  OPTIONAL { ?gw bboExt:default ?gwDefault . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edge ?edgeName ?srcName ?tgtName ?isImmediate WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?edge a bbo:SequenceFlow .
  ?edge tai:belongsTo ?choreo .
  ?edge bbo:has_sourceRef ?src .
  ?src a bboExt:ExclusiveGateway .
  ?edge bbo:has_targetRef ?tgt .
  OPTIONAL { ?edge bbo:name ?edgeName . }
  OPTIONAL { ?tgt bbo:name ?tgtName . }
  OPTIONAL { ?src bbo:name ?srcName . }
  OPTIONAL { ?edge bboExt:isImmediate ?isImmediate . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mf ?srcRef ?tgtRef ?msgRef WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?mf a bboExt:MessageFlow .
  ?mf tai:belongsTo ?choreo .
  OPTIONAL { ?mf bboExt:sourceRef ?srcRef . }
  OPTIONAL { ?mf bboExt:targetRef ?tgtRef . }
  OPTIONAL { ?mf bboExt:messageRef ?msgRef . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?elemName ?type ?isInterrupting WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "4ccc3fd711004f519782ac92e58f6ddd" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  {
    ?elem a bboExt:StartEvent .
    ?elem tai:belongsTo ?choreo .
    BIND(bboExt:StartEvent AS ?type)
    OPTIONAL { ?elem bboExt:isInterrupting ?isInterrupting . }
  }
  UNION
  {
    ?elem a bboExt:EndEvent .
    ?elem tai:belongsTo ?choreo .
    BIND(bboExt:EndEvent AS ?type)
  }
  UNION
  {
    ?elem a bboExt:Message .
    ?elem tai:belongsTo ?choreo .
    BIND(bboExt:Message AS ?type)
  }
  OPTIONAL { ?elem bbo:name ?elemName . }
}
